prompt_schema_text:
{
  "device": {
    "manufacturer": "string",
    "model": "string",
    "category_freeform": "string — manual's own product category words"
  },
  "entity_kind": "device|platform",
  "documented_version": "string — empty for ordinary devices",
  "ui_pages": [
    {
      "name": "string — page title",
      "purpose": "string",
      "appears_if_gate": {
        "verbatim": "full gate sentence or empty",
        "description_verbatim": "equipment noun phrase or empty",
        "functional_class": "acmi|mastervolt_inverter_charger|supported_hvac|empty"
      },
      "actions": [
        {
          "action": "string",
          "audience": "operator|installer_or_technician|either",
          "context": "daily|situational|emergency|commissioning|maintenance",
          "occasion": "optional — when/why from THIS text only; empty if unstated"
        }
      ]
    }
  ],
  "alarm_severity": [
    {
      "level_verbatim": "Critical|Important|Standard|Warning|…",
      "color_verbatim": "Red|Orange|Yellow|Blue|…"
    }
  ],
  "control_surfaces": [
    {
      "surface": "touchscreen|remote_panel_accessory|mobile_app_bluetooth|mobile_app_wifi_cloud|web_interface|physical_controls|rotary_selector|other",
      "location_class": "on_device|remote_wired|wireless|unknown",
      "optional_accessory": false,
      "label_verbatim": "optional short label from the manual",
      "path": "control_surfaces[0]"
    }
  ],
  "operator_actions": [
    {
      "action": "string — one verb phrase, one context",
      "audience": "operator|installer_or_technician|either",
      "context": "daily|situational|emergency|commissioning|maintenance",
      "options": ["optional — discrete option-value tails for the same setting"],
      "occasion": "optional — when/why from THIS text only; empty if unstated"
    }
  ],
  "networks": {
    "speaks": [
      {
        "name_verbatim": "string",
        "physical_or_wireless": "wired|wireless|unknown"
      }
    ],
    "bridges": [
      { "from": "string", "to": "string" }
    ]
  },
  "data_roles": {
    "exposes_data_to_network": false,
    "displays_data_from_other_devices": false,
    "controllable_from_network": false
  },
  "requires_devices": [
    {
      "description_verbatim": "string — one alternative product/dependency",
      "needed_for": "non-empty field path (control_surfaces[N] | data_roles.<key> | …)",
      "requirement_kind": "device|cable_or_consumable|software_app|commissioning_tool"
    }
  ],
  "safety_role": {
    "is_protective_device": false,
    "has_manual_override": false,
    "has_emergency_procedure": false
  },
  "protected_by": [
    { "description_verbatim": "string" }
  ],
  "protects": [
    { "description_verbatim": "string" }
  ],
  "supply_requirements": [
    { "description_verbatim": "string" }
  ],
  "evidence": [
    {
      "supports_field": "schema field path this evidence justifies",
      "manual_section": "section title or short heading",
      "note": "<=12-word paraphrase — never copy manual sentences"
    }
  ],
  "confidence": {
    "overall": 0.0,
    "notes": "string"
  }
}
